import base64, os
FILES = {
  'src/lib/krpano.ts': '',
  'src/app/api/projects/[id]/krpano/[tourId]/process/route.ts': '',
  'src/app/projects/[id]/krpano/page.tsx': '',
}
for rel, b64 in FILES.items():
    os.makedirs(os.path.dirname(rel), exist_ok=True)
    open(rel,'wb').write(base64.b64decode(b64))
    print('ecrit', rel)
print('=== 3 fichiers krpano (traitement repreneable) mis a jour ===')